INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$Company-level visitor identification$q$, $q$Matches anonymous website traffic to the companies behind it using IP-to-firmographic data matching.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$Person-level identification$q$, $q$Where data allows, identifies individual visitors and enriches them with contact details from third-party providers.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$Intent signal scoring$q$, $q$Surfaces buying-intent signals such as pricing-page visits and repeat sessions to help teams prioritize outreach.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$AI chat orchestration$q$, $q$Engages qualifying visitors with an on-site AI chatbot in real time while they are still browsing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$Slack alerting$q$, $q$Notifies the assigned sales rep instantly in Slack when a target account or high-intent visitor is detected.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$Automated outbound sequencing$q$, $q$Queues email and LinkedIn outreach automatically based on visitor behavior, reducing manual list-building.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$CRM and data provider integrations$q$, $q$Connects to common CRMs and enrichment sources like Clearbit, Apollo, and Bombora to keep pipeline data current.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$Combines identification and orchestration in one platform rather than requiring separate tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$Free tier makes it easy to test visitor identification value before paying$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$Real-time Slack alerts help reps act on hot accounts immediately$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$Multiple identification data sources can improve match coverage$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$AI chat and sequencing reduce manual outbound work for smaller sales teams$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$Person-level identification coverage is inherently limited by data availability and privacy constraints$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$Pricing scales with visitor volume, which can get expensive for high-traffic sites$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$Match accuracy depends on third-party data providers and can vary by industry or region$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$Best value requires an existing CRM and sales workflow to plug the orchestration into$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$What does Warmly actually do?$q$, $q$Warmly identifies anonymous companies and, where possible, individuals visiting a website, adds intent signals, and automatically triggers sales and marketing actions like Slack alerts, AI chat, email, and LinkedIn outreach.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$Is there a free version of Warmly?$q$, $q$Yes. Warmly offers a free plan that reveals a limited number of de-anonymized visitors per month, suitable for testing the product on smaller traffic volumes.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$How accurate is Warmly's visitor identification?$q$, $q$Accuracy varies by traffic source and company size. Company-level identification is generally more reliable than person-level identification, which depends on third-party contact data availability.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$Does Warmly integrate with my CRM?$q$, $q$Warmly integrates with common CRM and sales engagement tools so identified visitors and intent data can flow into existing pipeline workflows.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$Who is Warmly built for?$q$, $q$Warmly targets B2B sales, marketing, and revenue operations teams, particularly at SaaS companies, that want to convert anonymous website traffic into identified, actionable pipeline.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$How is Warmly different from other visitor identification tools?$q$, $q$Warmly emphasizes real-time orchestration on top of identification, automatically triggering outreach actions while the visitor is still on the site, rather than only providing an identification report.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$Does Warmly replace a sales development rep?$q$, $q$Warmly automates some outbound tasks like alerting and initial outreach, but it is generally used to augment a sales team rather than fully replace human sales development roles.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$Real-time inbound lead alerting$q$, $q$Sales teams get instant Slack notifications when a target account visits high-intent pages, allowing faster follow-up while interest is highest.$q$, $q$B2B sales development and account executive teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$Pipeline generation from existing website traffic$q$, $q$Marketing and revenue teams convert previously anonymous website visitors into identified leads and automated outreach sequences without new ad spend.$q$, $q$Demand generation and revenue operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$AI-assisted on-site engagement$q$, $q$An AI chatbot engages qualifying visitors in real time to answer questions and qualify interest before a rep gets involved.$q$, $q$SaaS companies with self-serve or sales-assisted funnels$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["Up to 500 de-anonymized visitors per month","Basic company identification","Limited orchestration features"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$Paid plans$q$, $q$Starting in the hundreds of dollars per month, scaling with visitor volume$q$, $q$monthly$q$, NULL, $q$["Higher monthly visitor limits","Full orchestration including AI chat, email, and LinkedIn sequencing","Slack and CRM integrations","Intent data enrichment from multiple providers"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Large-scale visitor volumes","Advanced AI agent and automation features","Dedicated support and onboarding"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$overview$q$, $q$What Is Warmly$q$, 2, ARRAY[$q$Warmly is a website visitor identification and sales orchestration platform built for B2B revenue teams. It watches traffic on a company's website, matches anonymous visitors to companies and, where data allows, individual contacts, and layers on intent signals so sales and marketing teams can see who is actively researching their product.$q$, $q$What sets Warmly apart from a plain visitor-identification tool is the orchestration layer on top of the data. Instead of only surfacing a report of who visited, Warmly can immediately act on that information: notifying a rep in Slack, starting a live AI chat with the visitor, queuing an email sequence, or adding the contact to a LinkedIn outreach campaign, all while the visitor is still browsing the site.$q$, $q$Founded around 2019 and based in San Francisco, Warmly went through Y Combinator and has raised institutional funding to build out its AI agent and orchestration capabilities, positioning itself against both traditional visitor-identification vendors and newer AI sales development tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Warmly's core capability is company and person-level visitor identification, pulling from multiple third-party data providers to enrich anonymous traffic with firmographic and contact details.$q$, $q$On top of identification, the platform adds real-time intent scoring so teams can prioritize accounts showing buying signals such as repeat visits, pricing-page views, or engagement with specific content.$q$, $q$Orchestration features let teams configure automated plays that trigger the moment a qualifying visitor is detected, including Slack alerts to the right rep, AI chatbot engagement on-site, automated email sequences, and LinkedIn connection or messaging workflows.$q$, $q$Warmly also integrates with common CRMs and sales engagement platforms so identified visitors and intent signals flow directly into existing pipeline and reporting processes rather than living in a separate dashboard.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4acb5d47-918c-44a6-ad53-de5ddb07110f', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Warmly uses a freemium pricing model. The free plan allows a limited number of de-anonymized visitors per month, which is enough for smaller sites or teams evaluating the product before committing to a paid tier.$q$, $q$Paid plans scale primarily on monthly visitor volume and the depth of orchestration features included, such as the number of automated plays, AI chat usage, and CRM or Slack integrations. Reported starting prices for paid tiers have been in the range of a few hundred dollars per month, with higher tiers and enterprise pricing available for companies with larger traffic volumes or more advanced automation needs.$q$, $q$As with most usage-scaled B2B tools, exact current pricing is best confirmed directly on Warmly's pricing page, since visitor thresholds and feature bundling have changed as the product has evolved.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$Shared team inbox$q$, $q$Centralizes WhatsApp conversations for multiple agents with assignment, tags, and internal collaboration notes.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$No-code chatbot builder$q$, $q$Automates FAQs, lead qualification, and common workflows using a visual flow builder without requiring code.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$Broadcast campaigns$q$, $q$Sends approved WhatsApp template messages to segmented contact lists for marketing and transactional updates.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$AI-assisted responses$q$, $q$Suggests replies and automates parts of customer conversations to speed up agent response time.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$E-commerce and CRM integrations$q$, $q$Connects WhatsApp conversations to platforms like Shopify, WooCommerce, and HubSpot for order and contact context.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$Contact segmentation and tagging$q$, $q$Organizes contacts by attributes and behavior to target broadcasts and personalize automated flows.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$Multi-agent role management$q$, $q$Assigns roles and permissions so teams can control who handles which conversations and campaigns.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$Purpose-built for the WhatsApp Business API rather than a generic omnichannel inbox$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$No-code chatbot builder makes automation accessible to non-technical teams$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$Strong fit for regions and industries where WhatsApp is the primary customer channel$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$Wide range of e-commerce and CRM integrations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$Flexible pay-as-you-go structure with no long-term cancellation penalties$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$No permanent free plan, only a short free trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$Total cost is harder to predict because WhatsApp per-message fees are billed on top of the subscription$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$Additional agent seats add extra cost on top of the base plan$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$Advanced automation and multi-number routing are locked behind higher-priced tiers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$What is WATI used for?$q$, $q$WATI is used to manage customer support, sales conversations, and marketing broadcasts over the WhatsApp Business API from a shared team inbox with chatbot automation.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$Does WATI charge for WhatsApp messages separately?$q$, $q$Yes. WATI's subscription covers platform access, while WhatsApp conversation fees set by Meta are billed on top, typically with a markup of around 20 percent over Meta's base rates.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$Is there a free trial for WATI?$q$, $q$WATI offers a 7-day free trial on its paid plans, but it does not offer a permanent free tier.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$What are WATI's main pricing tiers?$q$, $q$WATI is commonly sold in Growth, Pro, and Business tiers, differing by seat count, WhatsApp number channels, and access to advanced automation and routing features.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$Can WATI build chatbots without code?$q$, $q$Yes, WATI includes a no-code chatbot and flow builder for automating FAQs, lead capture, and common customer workflows.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$Does WATI integrate with Shopify or HubSpot?$q$, $q$Yes, WATI offers integrations with e-commerce platforms like Shopify and WooCommerce, as well as CRM tools like HubSpot, along with Zapier for broader connections.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$Who operates WATI?$q$, $q$WATI is operated by Clare.AI Limited, a company based in Hong Kong.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$WhatsApp customer support at scale$q$, $q$Support teams manage high volumes of WhatsApp conversations from a shared inbox with automated routing and chatbot deflection for common questions.$q$, $q$Customer support teams at e-commerce and service businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$WhatsApp marketing broadcasts$q$, $q$Marketing teams send approved template messages for promotions, order updates, and re-engagement campaigns to segmented WhatsApp audiences.$q$, $q$E-commerce and D2C marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$Automated lead qualification and booking$q$, $q$Businesses use no-code chatbot flows to qualify inbound leads or book appointments over WhatsApp without manual agent involvement.$q$, $q$Sales teams and service businesses like clinics or real estate agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$Growth$q$, $q$From around $59 per month (annual billing)$q$, $q$monthly or annual$q$, NULL, $q$["Single WhatsApp channel","Fixed number of agent seats","Basic broadcast and inbox features"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$Pro$q$, $q$From around $119 per month (annual billing)$q$, $q$monthly or annual$q$, NULL, $q$["Advanced chatbot and forms","Retargeting campaigns","AI automation features","Additional agent seats available"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$Business$q$, $q$From around $279 per month (annual billing)$q$, $q$monthly or annual$q$, NULL, $q$["Multiple WhatsApp numbers","Round-robin conversation routing","Dedicated success manager","Additional agent seats available"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$overview$q$, $q$What Is WATI$q$, 2, ARRAY[$q$WATI is a WhatsApp Business API platform that gives businesses a shared inbox, automation tools, and broadcast capabilities for managing customer conversations over WhatsApp at scale. The name stands for WhatsApp Team Inbox, reflecting its origin as a tool for teams to collaboratively manage WhatsApp support and sales chats.$q$, $q$The platform is built and operated by Clare.AI Limited, a Hong Kong-based company, and has grown to serve a large base of businesses worldwide, with particularly strong adoption in markets where WhatsApp is the dominant messaging channel for commerce and customer service.$q$, $q$Beyond basic messaging, WATI layers on no-code chatbot building, AI-assisted responses, contact segmentation, and integrations with e-commerce and CRM tools, positioning it as a full customer engagement platform built specifically around the WhatsApp Business API rather than a generic omnichannel inbox.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$A shared team inbox lets multiple agents manage WhatsApp conversations from a single dashboard, with assignment, tagging, and internal notes to coordinate handoffs.$q$, $q$No-code chatbot and flow builders allow businesses to automate FAQs, lead capture, appointment booking, and order status updates without writing code.$q$, $q$Broadcast campaign tools support sending WhatsApp template messages for marketing, promotions, and transactional notifications to segmented contact lists, subject to WhatsApp's opt-in and template approval rules.$q$, $q$Integrations with platforms like Shopify, WooCommerce, HubSpot, and Zapier connect WhatsApp conversations to existing e-commerce and CRM data.$q$, $q$AI features assist agents with suggested replies and automate parts of the conversation flow, reducing manual response time for common queries.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6defa3eb-e961-45d0-b2f3-df7356237cfc', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$WATI charges a monthly or annual subscription fee for platform access, typically structured across three tiers, commonly named Growth, Pro, and Business, that differ by the number of included agent seats, WhatsApp number channels, and available automation features.$q$, $q$On annual billing, published pricing has generally ranged from roughly $50 to $60 per month for the entry Growth tier up to several hundred dollars per month for the Business tier, with additional agent seats available at extra cost on each plan.$q$, $q$Separate from the platform subscription, WhatsApp itself charges per-conversation fees that vary by the recipient's country and the message category (marketing, utility, or authentication). WATI, like other WhatsApp Business Solution Providers, passes these fees through with a markup, commonly cited at around 20 percent above Meta's base rates, so total cost depends heavily on messaging volume and geography.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Double-entry accounting$q$, $q$Provides a full accounting system with a chart of accounts and standard financial reports for small businesses.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Unlimited invoicing and estimates$q$, $q$Creates and sends professional invoices and estimates with recurring billing and online payment options.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Receipt scanning$q$, $q$Extracts expense data automatically from photographed or uploaded receipts.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Bank connections$q$, $q$Automatically imports and categorizes transactions from linked bank and credit card accounts on the Pro plan.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Wave Payments$q$, $q$Lets customers pay invoices online by card or bank transfer directly from the invoice.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Wave Payroll add-on$q$, $q$Runs employee and contractor payroll with automatic tax calculations and filings in supported regions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Financial reporting$q$, $q$Generates profit and loss, balance sheet, and cash flow reports for tracking business performance.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Free Starter plan covers real double-entry accounting and unlimited invoicing at no cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Simple, approachable interface aimed at non-accountants$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Backed by H&R Block, adding financial stability and tax expertise$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Optional payroll and human bookkeeping services scale up as a business grows$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$No per-invoice or per-client limits on the free plan$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Free plan lacks automatic bank feeds and built-in receipt scanning without add-ons$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Fewer advanced features and integrations compared to QuickBooks or Xero$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Payroll is only available in a limited set of US states and Canadian provinces$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Customer support on the free plan is more limited than on paid tiers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Is Wave accounting software really free?$q$, $q$Yes, the Starter plan is free and includes double-entry bookkeeping, unlimited invoicing, and expense tracking, though it lacks automatic bank feeds and built-in receipt scanning.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$How much does Wave Pro cost?$q$, $q$Wave Pro costs around 19 US dollars per month (about 25 Canadian dollars), adding automatic bank imports, receipt scanning, and removal of Wave branding.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Does Wave offer payroll?$q$, $q$Yes, Wave Payroll is a separate add-on with a base monthly fee plus a per-employee or per-contractor charge, available in supported US states and Canadian provinces.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Who owns Wave?$q$, $q$Wave has been owned by H&R Block since 2019, when H&R Block acquired the company for approximately 405 million US dollars.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Who is Wave best suited for?$q$, $q$Wave is best suited for freelancers, sole proprietors, and very small businesses that need straightforward accounting and invoicing without enterprise-level complexity.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Can I accept online payments through Wave?$q$, $q$Yes, Wave Payments lets customers pay invoices online by card or bank transfer directly from the invoice.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Where is Wave headquartered?$q$, $q$Wave is headquartered in Toronto, Ontario, Canada.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Free small business bookkeeping$q$, $q$Solo entrepreneurs and freelancers track income and expenses and manage double-entry books without paying for accounting software.$q$, $q$Freelancers and sole proprietors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Professional invoicing and online payments$q$, $q$Small businesses send unlimited branded invoices and let customers pay online, speeding up collections.$q$, $q$Small service businesses and consultants$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Payroll for very small teams$q$, $q$Businesses with a small number of employees or contractors run payroll and handle payroll tax filings through the Wave Payroll add-on.$q$, $q$Small businesses with a handful of employees or contractors$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Starter$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["Unlimited invoicing and estimates","Manual bank statement import","Basic expense tracking","Financial reports"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Pro$q$, $q$$19 per month (approximately $25 CAD)$q$, $q$monthly$q$, NULL, $q$["Automatic bank transaction imports","Built-in receipt scanning","Multiple user roles","No Wave branding on invoices"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Payroll add-on$q$, $q$Base fee plus per-employee or per-contractor charge$q$, $q$monthly$q$, NULL, $q$["Employee and contractor payments","Automatic payroll tax calculations","Tax filings in supported regions"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$overview$q$, $q$What Is Wave$q$, 2, ARRAY[$q$Wave is accounting and invoicing software designed for freelancers, sole proprietors, and small businesses that need to manage bookkeeping without the cost or complexity of larger enterprise accounting platforms. Founded in Toronto in 2009 and launched publicly in 2010, Wave built its early reputation on offering core accounting and invoicing tools for free, monetizing instead through optional payment processing and payroll services.$q$, $q$In 2019, tax preparation giant H&R Block acquired Wave for roughly 405 million US dollars, and Wave has continued to operate as part of H&R Block since then, retaining its own brand, product, and Toronto base while gaining access to H&R Block's resources and tax expertise.$q$, $q$Today Wave serves hundreds of thousands of small businesses with a product suite spanning accounting, invoicing, receipt scanning, online payments, and payroll, aimed squarely at very small businesses and solo operators rather than mid-market or enterprise companies.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Wave's core accounting engine supports double-entry bookkeeping, a chart of accounts, and financial reports like profit and loss, balance sheet, and cash flow statements, suitable for tracking a small business's full financial picture.$q$, $q$Unlimited invoicing and estimates let users create and send professional invoices, set up recurring billing, and accept online payments directly from an invoice when Wave Payments is enabled.$q$, $q$Receipt scanning, available as a paid add-on on the free plan and included in Pro, lets users photograph or upload receipts and have expense data extracted automatically.$q$, $q$Wave Payroll, sold as a separate add-on, handles employee and contractor payments, automatic payroll tax calculations, and tax filings in supported regions.$q$, $q$Bank connections on the Pro plan automatically import and categorize transactions from linked bank and credit card accounts, reducing manual data entry compared to the free Starter plan.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Wave's Starter plan is free and covers manual bookkeeping, unlimited invoicing, and expense tracking, though it requires manual bank statement imports rather than automatic bank feeds and does not include receipt scanning without a paid add-on.$q$, $q$The Pro plan costs around 19 US dollars per month (about 25 Canadian dollars) and adds automatic bank transaction imports, built-in receipt scanning, multiple user roles, and removes Wave branding from invoices and other customer-facing documents.$q$, $q$Wave Payroll is priced separately from the accounting plans, with a base monthly fee plus a per-employee or per-contractor charge, and Wave also offers optional professional bookkeeping services with human bookkeepers at a higher monthly price point for businesses that want ongoing hands-on support.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$Asterisk-based PBX engine$q$, $q$Built on the widely used Asterisk telephony engine combined with Kamailio and RTPEngine for carrier-grade call handling.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$API-first architecture$q$, $q$Exposes REST APIs, WebRTC, WebSockets, and webhooks for deep integration with external applications.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$Call center queues$q$, $q$Provides call routing and queueing features for support and sales teams handling inbound call volume.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$Team chat and video conferencing$q$, $q$Combines internal messaging and video meetings alongside traditional voice calling in one platform.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$Flexible deployment$q$, $q$Runs on bare metal, virtual machines, or containers, giving organizations control over hosting.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$Voicemail and presence$q$, $q$Includes standard PBX features like voicemail and user presence status across the organization.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$White-label option via Wazo.io$q$, $q$Offers a commercial, white-label version aimed at MSPs and carriers reselling hosted UC services.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$Free and open source under GPLv3, with no per-seat licensing cost for the core platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$API-first design makes it well suited for developers embedding communications into custom applications$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$Built on the mature, widely deployed Asterisk PBX engine$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$Flexible deployment options including bare metal, VMs, and containers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$White-label commercial option available for MSPs and carriers wanting a supported, brandable product$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$Self-hosting requires telecom and Linux systems expertise, unlike plug-and-play hosted UCaaS products$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$No published self-serve pricing for the commercial white-label offering$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$Smaller ecosystem and community compared to larger open source or commercial UC platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$Documentation and support quality can vary between the open source community edition and paid support$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$Is Wazo free to use?$q$, $q$The core Wazo Platform is free and open source under the GPLv3 license. Commercial hosting, support, and white-label offerings through Wazo.io are separately priced.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$What is Wazo built on?$q$, $q$Wazo is built primarily on the Asterisk PBX engine, combined with components like Kamailio and RTPEngine for call routing and media handling.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$Who uses Wazo?$q$, $q$Wazo is used by developers building custom communications products, telecom-savvy organizations wanting to avoid vendor lock-in, and managed service providers reselling hosted UC services.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$Where did Wazo come from?$q$, $q$Wazo originated from the XiVO open source telephony project started in France in 2005 and was relaunched as Wazo in November 2016 by a team in Quebec City, Canada.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$Can Wazo be self-hosted?$q$, $q$Yes, Wazo can be deployed on bare metal servers, virtual machines, or containers, and organizations are free to self-host the open source platform.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$Does Wazo support video calling?$q$, $q$Yes, Wazo supports audio and video calling, team chat, and conferencing alongside its core telephony features.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$What is the difference between the open source project and Wazo.io?$q$, $q$The open source project at wazo-platform.org is the free, self-hostable core, while Wazo.io is a commercial, white-label version aimed at MSPs and carriers who want hosted, brandable UC services.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$Custom communications infrastructure$q$, $q$Developers use Wazo's APIs to embed calling, messaging, and video into their own applications and workflows.$q$, $q$Software developers and telecom engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$Self-hosted business phone system$q$, $q$Organizations deploy Wazo on their own infrastructure to run a full-featured PBX without depending on a proprietary hosted vendor.$q$, $q$IT teams at telecom-savvy organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$White-label UC for MSPs and carriers$q$, $q$Managed service providers and carriers use the Wazo.io commercial offering to resell hosted unified communications under their own brand.$q$, $q$Managed service providers and telecom carriers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$Open Source (self-hosted)$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["Full PBX and UC feature set","GPLv3 licensed core components","Community support","Self-managed deployment"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$Wazo.io white-label$q$, $q$Custom, quoted per deployment or seat$q$, $q$custom$q$, NULL, $q$["Managed or white-label hosting","Multi-tenant management for MSPs and carriers","Commercial support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$overview$q$, $q$What Is Wazo$q$, 2, ARRAY[$q$Wazo Platform is an open source unified communications and PBX system for building programmable IP telephony infrastructure. Rather than functioning as a closed, proprietary phone system, Wazo is designed API-first, giving developers REST APIs, WebRTC, and webhooks to integrate calling, messaging, and video into their own applications and workflows.$q$, $q$The project traces its roots back to XiVO, an open source telephony system started in France in 2005, which later merged with Avencall before its team relaunched as Wazo in November 2016 out of Quebec City, Canada, following the shutdown of Proformatique Inc.$q$, $q$Wazo is built on the Asterisk PBX engine combined with Kamailio and RTPEngine, and its core distinctive components are released under the GPLv3 license, making the platform free to self-host, inspect, and modify.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Wazo delivers class 5 telephony features including audio and video calling, voicemail, presence, and mobility for remote or softphone users, comparable to what a carrier-grade phone system provides.$q$, $q$Team chat and conferencing tools support internal collaboration alongside traditional voice calling within the same platform.$q$, $q$Call center functionality includes queues and routing logic suitable for support and sales teams handling inbound call volume.$q$, $q$An API-first architecture exposes REST APIs, WebRTC, WebSockets, and webhooks so developers can build custom integrations, embed calling into other software, or automate communications workflows.$q$, $q$Flexible deployment supports bare metal servers, virtual machines, or containers, giving organizations control over where and how the platform runs.$q$, $q$A related commercial offering, Wazo.io, provides a white-label version of the platform aimed at managed service providers and carriers who want to resell hosted UC services under their own brand.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Wazo Platform is free and open source under the GPLv3 license, so there is no license fee to self-host and run the system; costs come from your own infrastructure and any internal engineering time needed to deploy and maintain it.$q$, $q$Organizations that want commercial support, managed hosting, or a white-label multi-tenant offering can use the Wazo.io commercial product, which is aimed at MSPs and carriers and is typically priced per deployment or per seat through direct sales rather than published self-serve pricing.$q$, $q$Because Wazo is infrastructure software rather than a typical SaaS product, total cost of ownership depends heavily on deployment scale, hosting choices, and whether an organization opts for community support or a paid support contract.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('688d8396-0ab3-420a-ba26-729121f64809', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$SIEM log analysis$q$, $q$Aggregates and correlates log data across endpoints and cloud workloads for centralized threat detection.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$XDR endpoint protection$q$, $q$Extends detection and response capabilities across endpoints, cloud, and containers from a unified platform.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$File integrity monitoring$q$, $q$Detects unauthorized changes to critical files and system configurations.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$Vulnerability detection$q$, $q$Scans installed software for known vulnerabilities to help prioritize patching.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$Configuration assessment$q$, $q$Checks systems against security benchmarks like CIS to identify misconfigurations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$Regulatory compliance reporting$q$, $q$Supports compliance monitoring and reporting for frameworks such as PCI DSS, HIPAA, and GDPR.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$Active response automation$q$, $q$Automatically executes response actions, such as blocking a malicious IP, when threats are detected.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$Fully open source with no licensing cost, unlike most commercial SIEM and XDR platforms$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$Broad feature set spanning log analysis, file integrity, vulnerability, and compliance monitoring$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$Active open source community with frequent updates and extensive documentation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$Integrates with major cloud providers and container platforms$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$No vendor lock-in since organizations fully control their own deployment and data$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$Self-hosted deployments require security and infrastructure expertise to set up and maintain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$Managed Wazuh Cloud pricing is not publicly listed and requires a sales quote$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$Scaling log ingestion for large environments can require significant infrastructure investment$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$Lacks some of the polished enterprise support and SLAs offered by large commercial SIEM vendors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$Is Wazuh completely free?$q$, $q$Yes, the core Wazuh platform is free and open source with no licensing cost. Costs come from your own hosting infrastructure, or from the optional paid Wazuh Cloud managed service.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$What is the difference between Wazuh's SIEM and XDR capabilities?$q$, $q$Wazuh's SIEM functionality focuses on aggregating and correlating log data for threat detection and compliance, while its XDR functionality extends detection and automated response across endpoints and cloud workloads in a unified platform.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$Does Wazuh support compliance frameworks?$q$, $q$Yes, Wazuh includes monitoring and reporting features that map to compliance frameworks such as PCI DSS, HIPAA, and GDPR.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$Can Wazuh be deployed in the cloud?$q$, $q$Yes, Wazuh agents and integrations support major cloud providers like AWS, Azure, and Google Cloud, and Wazuh also offers a managed Wazuh Cloud hosting option.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$Who typically uses Wazuh?$q$, $q$Wazuh is used by security operations center teams, managed security service providers, and IT teams that need centralized threat detection and compliance monitoring without commercial SIEM licensing costs.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$How is Wazuh installed?$q$, $q$Wazuh uses lightweight agents installed on endpoints that send data to a central Wazuh server, with results visualized through a dashboard built on OpenSearch.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$How much does Wazuh Cloud cost?$q$, $q$Wazuh Cloud, the managed hosting option, uses custom pricing based on data volume and support needs rather than fixed published rates, so pricing requires contacting Wazuh directly.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$Centralized threat detection$q$, $q$Security teams monitor logs, files, and system activity across their infrastructure from a single Wazuh dashboard to detect and investigate threats.$q$, $q$Security operations center (SOC) teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$Regulatory compliance monitoring$q$, $q$Organizations use Wazuh's compliance mapping and reporting to support audits for frameworks like PCI DSS and HIPAA.$q$, $q$IT and compliance teams in regulated industries$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$Cost-effective SIEM replacement$q$, $q$Companies replace or supplement expensive commercial SIEM licenses with Wazuh's free, self-hosted open source platform.$q$, $q$Security teams at cost-conscious or infrastructure-savvy organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$Open Source (self-hosted)$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["Full SIEM and XDR feature set","Self-managed agents, server, and dashboard","Community support","No licensing cost"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$Wazuh Cloud$q$, $q$Custom, quote-based$q$, $q$custom$q$, NULL, $q$["Managed hosting of the Wazuh stack","Vendor-provided support","Scalable data volume options"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$overview$q$, $q$What Is Wazuh$q$, 2, ARRAY[$q$Wazuh is a free, open source security platform that combines SIEM and XDR functionality to help organizations detect threats, monitor compliance, and respond to security incidents across endpoints and cloud workloads. The company behind the project was founded in 2015 and is based in San Jose, California.$q$, $q$The platform grew out of the open source intrusion detection ecosystem, evolving from an earlier OSSEC-based project into a broader, independently maintained security monitoring stack with its own agent, server, and dashboard components.$q$, $q$Because the entire stack is open source with no licensing fee, Wazuh has become one of the most widely adopted free security platforms, used by security teams that want full control over their data or a lower-cost alternative to commercial SIEM tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Lightweight agents deployed on servers, workstations, cloud instances, and containers collect logs, system inventory, and file integrity data for centralized analysis.$q$, $q$Log data analysis and correlation identify suspicious activity and security events across the monitored environment, feeding into a central alerting and dashboard system.$q$, $q$File integrity monitoring tracks changes to critical files and configurations, helping detect unauthorized modifications or tampering.$q$, $q$Vulnerability detection scans installed software against known vulnerability databases to flag outdated or exploitable packages.$q$, $q$Configuration assessment checks systems against security benchmarks like CIS to identify misconfigurations.$q$, $q$Compliance support maps monitoring and reporting capabilities to regulatory frameworks such as PCI DSS, HIPAA, and GDPR.$q$, $q$Active response features can automatically take action, such as blocking an IP address, when certain threats are detected.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e60f5b02-2824-43ca-a32f-0fbe7c20da50', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Wazuh's core platform, including the agents, server, and dashboard, is free and open source with no licensing cost, so organizations can deploy the full SIEM and XDR stack on their own infrastructure at no software charge.$q$, $q$Costs for a self-hosted deployment come from infrastructure (servers, storage, and scaling for log volume) and internal engineering time to deploy, tune, and maintain the platform.$q$, $q$For organizations that prefer a managed option, Wazuh Cloud offers hosted deployment and support, priced through custom quotes based on data volume, number of agents, and support level rather than fixed published pricing.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$Real-time multi-user drawing$q$, $q$Allows any number of users to draw on the same board simultaneously with live syncing.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$Persistent boards$q$, $q$Automatically saves board state so drawings remain accessible after closing and reopening the link.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$Link-based private boards$q$, $q$Lets users create boards with random names that function as a private space accessible only via the shared URL.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$Basic drawing toolkit$q$, $q$Provides freehand drawing, shapes, text, and image insertion for sketching and diagramming.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$Self-hosting support$q$, $q$Open source code can be deployed on a private server or via Docker for full control over data.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$No sign-up required$q$, $q$Users can start drawing and collaborating immediately without creating an account.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$Completely free to use with no paid tiers or subscriptions$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$No account or sign-up required to start collaborating$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$Open source and self-hostable for organizations that want data control$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$Simple, lightweight interface that loads quickly and is easy to learn$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$Translated into more than 15 languages for broad accessibility$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$Lacks advanced features, templates, and integrations found in commercial whiteboard tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$No formal access controls or authentication on the public hosted version beyond the board link$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$Maintained largely by a single independent developer, which may affect long-term support pace$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$Not designed for enterprise use cases like SSO, audit logs, or team administration$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$Is WBO really free?$q$, $q$Yes, WBO is completely free to use on the public hosted instance, and the underlying code is open source so anyone can self-host it for free as well.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$Do I need an account to use WBO?$q$, $q$No, WBO does not require an account or sign-up. You simply create a board and share its URL with collaborators.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$Who maintains WBO?$q$, $q$WBO is built and maintained by independent developer Ophir Lojkine under the open source project name whitebophir.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$Can I self-host WBO?$q$, $q$Yes, the whitebophir code is open source under the AGPLv3 license and can be deployed on your own server, including via Docker.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$How private are WBO boards?$q$, $q$Boards can be created with a random, hard-to-guess name so they function as a private space accessible only to people who have the link, though there is no formal login-based access control.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$What can WBO be used for?$q$, $q$WBO is commonly used for teaching, brainstorming, quick diagramming, and general collaborative sketching where a lightweight, free tool is sufficient.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$How does WBO compare to tools like Miro?$q$, $q$WBO is much simpler and entirely free, but it lacks the templates, integrations, and enterprise features found in commercial whiteboard platforms like Miro or FigJam.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$Classroom and remote teaching$q$, $q$Teachers use WBO as a free real-time drawing surface for explaining concepts and collaborating with students remotely.$q$, $q$Teachers and remote educators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$Quick team brainstorming$q$, $q$Small teams share a WBO board link for ad hoc brainstorming or diagramming without needing to set up an account.$q$, $q$Small teams and informal work groups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$Self-hosted private whiteboard$q$, $q$Technical users or organizations deploy their own instance of WBO for internal use, keeping full control of their data.$q$, $q$Developers and privacy-conscious organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$Free (hosted)$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["Real-time collaborative drawing","Persistent boards","No account required","Unlimited boards"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$Self-hosted$q$, $q$$0 (own infrastructure costs)$q$, $q$n/a$q$, NULL, $q$["Full control over data and hosting","Open source AGPLv3 code","Docker deployment support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$overview$q$, $q$What Is WBO$q$, 2, ARRAY[$q$WBO, short for Whiteboard Online, is a free, open source collaborative whiteboard that lets multiple people draw on the same virtual canvas in real time. It is built and maintained by independent developer Ophir Lojkine, with the code published under the project name whitebophir on GitHub.$q$, $q$The publicly hosted version runs at wbo.ophir.dev and requires no account or sign-up: users simply create a board and share its URL with collaborators to start drawing together, with the board's state automatically saved so work persists between sessions.$q$, $q$Because it is a lightweight, single-developer open source project rather than a funded company, WBO does not have the enterprise features, integrations, or support structure of commercial whiteboard tools, but it offers a genuinely free and self-hostable alternative for simple collaborative sketching.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Real-time collaborative drawing lets any number of connected users sketch on the same board simultaneously, with updates synced live to everyone viewing it.$q$, $q$Persistent board state means drawings are automatically saved, so a board's content survives after users close their browser and can be revisited later using the same URL.$q$, $q$Link-based access control lets users create boards with random, hard-to-guess names, functioning as a lightweight private space without requiring formal accounts or logins.$q$, $q$Basic drawing tools cover freehand drawing, shapes, text, and image insertion, enough for sketching, diagramming, and teaching use cases.$q$, $q$Self-hosting support lets technical users or organizations deploy their own private instance of WBO on their own server, including via Docker, for full control over data and availability.$q$, $q$Multi-language support with translations in more than 15 languages makes the tool accessible to a broad international audience.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$WBO is entirely free to use on the public hosted instance at wbo.ophir.dev, with no paid plans, subscriptions, or premium feature tiers.$q$, $q$Because the underlying whitebophir code is open source under the AGPLv3 license, anyone can also self-host their own private instance for free, only incurring their own server hosting costs.$q$, $q$There is no enterprise or commercial pricing tier, reflecting WBO's nature as an independent open source project rather than a commercial software company.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6dfb48ec-e418-4fe0-93c7-9323f4ba54ce', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Cloud VoIP phone system$q$, $q$Replaces a practice's traditional phone system with cloud-based calling, recording, and team chat.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Two-way texting$q$, $q$Lets staff and patients communicate via text for scheduling, reminders, and quick questions.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Practice management integration$q$, $q$Surfaces patient records automatically when a call or text comes in by integrating with practice management software.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Online scheduling and reminders$q$, $q$Allows patients to book appointments online and receive automated reminders to reduce no-shows.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Text-to-pay and payment processing$q$, $q$Lets patients pay bills directly from a text message, along with card terminal and card-on-file options.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Insurance verification$q$, $q$Helps front-desk staff confirm patient insurance coverage ahead of appointments.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Review and reputation management$q$, $q$Automates review requests and helps practices monitor and respond to patient feedback.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Consolidates phone, scheduling, and payments into one platform purpose-built for healthcare practices$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Deep practice management software integrations surface patient context automatically$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Text-to-pay and flexible payment options can speed up patient bill collection$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Strong focus on dental and veterinary workflows rather than generic business communication$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Backed by a large, publicly traded company with ongoing product investment$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Pricing is not published and requires a sales quote, making upfront cost comparisons harder$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Primarily built for healthcare verticals, so it may be less suited to unrelated industries$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Full value depends on integration with a compatible practice management system$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Feature bundles and pricing can vary significantly by practice size and specialty$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$What is Weave used for?$q$, $q$Weave is used by dental, veterinary, and other healthcare practices to manage phone calls, texting, scheduling, reminders, and payments in one platform integrated with practice management software.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$How much does Weave cost?$q$, $q$Weave uses custom, quote-based pricing rather than published rates, with third-party estimates commonly in the range of 100 to 500 dollars per month depending on practice size and features.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Does Weave replace my office phone system?$q$, $q$Yes, Weave provides a cloud-based VoIP phone system intended to replace a practice's traditional phone line, adding features like call recording and missed-call auto-text.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Can patients pay their bill through Weave?$q$, $q$Yes, Weave includes payment tools such as text-to-pay, card terminals, manual card entry, and card-on-file billing.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Does Weave integrate with practice management software?$q$, $q$Yes, Weave integrates with most dental and veterinary practice management software to display patient information automatically during calls and texts.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Is Weave a public company?$q$, $q$Yes, Weave Communications is publicly traded on the New York Stock Exchange under the ticker WEAV.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Where is Weave headquartered?$q$, $q$Weave is headquartered in Lehi, Utah, United States.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Dental practice front-desk communication$q$, $q$Dental offices use Weave to manage phone calls, texting, and scheduling while automatically pulling up patient records for staff.$q$, $q$Dental practices and front-office staff$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Veterinary appointment and payment management$q$, $q$Veterinary clinics use Weave's scheduling, reminders, and text-to-pay features to reduce no-shows and speed up billing.$q$, $q$Veterinary practices$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Patient review and reputation management$q$, $q$Healthcare practices automate review requests and monitor online reputation across review platforms through Weave.$q$, $q$Practice managers and marketing staff at healthcare practices$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$Custom$q$, $q$Quote-based, commonly $100 to $500 per month$q$, $q$monthly$q$, NULL, $q$["Cloud VoIP phone system","Two-way texting and team chat","Online scheduling and reminders","Payment processing and text-to-pay","Practice management integrations"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$overview$q$, $q$What Is Weave$q$, 2, ARRAY[$q$Weave is an all-in-one communication, scheduling, and payments platform built specifically for dental, veterinary, and other healthcare practices. Founded in 2008 and headquartered in Lehi, Utah, the company has grown into a publicly traded business serving thousands of practices across North America.$q$, $q$At its core, Weave replaces a practice's traditional phone system with a cloud-based VoIP solution that integrates directly with practice management software, so staff see patient records and appointment history the moment a call or text comes in.$q$, $q$Beyond phones and texting, Weave bundles in online scheduling, automated reminders, review management, and a suite of payment tools, aiming to consolidate the many separate vendors a small healthcare practice might otherwise use into one platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Cloud-based VoIP phone service includes call recording, missed-call auto-text, and team chat, replacing a practice's legacy phone system with one built for healthcare front desks.$q$, $q$Practice management integrations pull up patient records automatically when a call or text comes in, saving front-desk staff from manually looking up patient information.$q$, $q$Online scheduling and automated appointment reminders reduce no-shows and let patients book appointments without calling the office directly.$q$, $q$Insurance verification workflows help front-desk staff confirm patient coverage before appointments, reducing billing surprises.$q$, $q$Payment tools include card terminals, manual card entry, card-on-file billing, buy-now-pay-later style payment plans, and text-to-pay links for settling bills via text message.$q$, $q$Review generation and reputation management features help practices collect and respond to patient reviews across platforms.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('122093a2-2cf8-46b9-8fcf-07070f5d37e2', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Weave does not publish fixed pricing; the platform is sold through a custom, quote-based model tailored to a practice's size, specialty, and the specific mix of phone, scheduling, and payment features selected.$q$, $q$Third-party estimates commonly place typical monthly costs somewhere in the range of 100 to 500 dollars per practice, though actual pricing depends heavily on the number of locations, phone lines, and add-on modules chosen.$q$, $q$Prospective customers generally need to request a demo and quote directly from Weave's sales team rather than self-serve signing up, which is typical for practice management and healthcare communication software in this category.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Hybrid vector and keyword search$q$, $q$Combines semantic vector search with BM25 keyword search in a single query for improved relevance.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Built-in RAG support$q$, $q$Connects retrieved results directly to large language models for retrieval-augmented generation pipelines.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Embedding model integrations$q$, $q$Integrates with providers like OpenAI, Cohere, and Hugging Face to generate vector embeddings automatically.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Structured filtering$q$, $q$Combines vector similarity search with traditional metadata filters for more precise query results.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Reranking$q$, $q$Improves the ordering of retrieved results after initial vector search, boosting relevance for downstream applications.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Multi-language client libraries$q$, $q$Provides SDKs in Python, JavaScript, Go, and Java for integration across common development stacks.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Horizontal scaling$q$, $q$Supports cloud-native, fault-tolerant scaling for production workloads with large vector datasets.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Open source core is free to self-host under the Apache 2.0 license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Hybrid search combining vector and keyword search improves relevance over pure vector search alone$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Built-in integrations with major embedding model providers reduce setup complexity$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Strong fit for retrieval-augmented generation applications built on large language models$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Managed Weaviate Cloud option removes the need to operate infrastructure for teams that prefer it$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Self-hosting at scale requires infrastructure and operational expertise$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Cloud pricing based on vector dimensions can be harder to estimate upfront than flat per-seat pricing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Competes in a crowded vector database market with strong alternatives like Pinecone and Qdrant$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Some advanced features and higher-tier support require paid Weaviate Cloud plans$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Is Weaviate free to use?$q$, $q$Yes, the core Weaviate database is open source and free to self-host under the Apache 2.0 license. Weaviate Cloud also offers a free sandbox tier alongside paid plans.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$What is Weaviate used for?$q$, $q$Weaviate is used to build semantic search, recommendation systems, chatbots, and retrieval-augmented generation applications powered by large language models.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Does Weaviate support hybrid search?$q$, $q$Yes, Weaviate combines vector similarity search with keyword-based BM25 search in a single hybrid query.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$How much does Weaviate Cloud cost?$q$, $q$Weaviate Cloud pricing generally ranges from around 25 to 200 dollars per month on the Standard tier, with Professional and Business Critical tiers starting around 135 and 450 dollars per month respectively, plus custom enterprise pricing.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Who founded Weaviate?$q$, $q$Weaviate was founded in 2019 by Bob van Luijt (CEO) and Etienne Dilocker (CTO) and is headquartered in Amsterdam, Netherlands.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$What embedding models does Weaviate support?$q$, $q$Weaviate integrates with popular embedding model providers such as OpenAI, Cohere, and Hugging Face, along with support for custom or self-hosted embedding models.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Can Weaviate be self-hosted?$q$, $q$Yes, since the core database is open source under Apache 2.0, it can be self-hosted on a developer's own infrastructure as an alternative to using Weaviate Cloud.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Semantic search applications$q$, $q$Developers build search experiences that understand meaning and context rather than relying solely on exact keyword matches.$q$, $q$Application developers and search engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Retrieval-augmented generation for LLMs$q$, $q$AI teams use Weaviate to retrieve relevant context that is fed into large language models to improve accuracy and reduce hallucination.$q$, $q$AI and machine learning engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Recommendation and personalization systems$q$, $q$Companies use vector similarity search to power product or content recommendations based on user behavior and preferences.$q$, $q$Product and data engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Open Source (self-hosted)$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["Full vector database functionality","Apache 2.0 license","Self-managed deployment","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Weaviate Cloud Standard$q$, $q$Around $25 to $200 per month$q$, $q$monthly$q$, NULL, $q$["Managed hosting","Priced by vector dimensions stored","Free sandbox tier for experimentation"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Professional / Business Critical$q$, $q$From around $135 to $450+ per month$q$, $q$monthly$q$, NULL, $q$["Production-grade availability","Higher support levels","Scalable for larger workloads"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Dedicated deployments","Custom SLAs","Large-scale enterprise support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$overview$q$, $q$What Is Weaviate$q$, 2, ARRAY[$q$Weaviate is an open source, AI-native vector database built for semantic search, retrieval-augmented generation, and other applications powered by large language models. Founded in 2019 by Bob van Luijt and Etienne Dilocker and headquartered in Amsterdam, the company has grown into one of the better-known independent vector database providers as demand for AI infrastructure has expanded.$q$, $q$The core Weaviate database stores both structured data objects and their vector embeddings together, allowing developers to combine vector similarity search with traditional filtering and keyword search in a single query rather than stitching together separate systems.$q$, $q$Weaviate is released under the Apache 2.0 license, making it free to self-host, while the company also operates Weaviate Cloud, a managed hosting service, and has raised significant venture capital, including a 50 million dollar Series B round in 2023, to fund product development.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Hybrid search combines vector similarity search with keyword-based BM25 search in a single query, improving relevance for use cases where pure semantic search alone falls short.$q$, $q$Built-in generative search modules connect retrieved results directly to large language models, streamlining retrieval-augmented generation pipelines without extra integration work.$q$, $q$Model integrations support popular embedding providers such as OpenAI, Cohere, and Hugging Face, letting developers generate and store vectors without managing separate embedding infrastructure.$q$, $q$Structured filtering allows queries to combine vector similarity with traditional metadata filters, such as category or date range, for more precise results.$q$, $q$Reranking support improves result ordering after initial retrieval, which is useful for RAG applications where result quality directly affects LLM output.$q$, $q$Multi-language client libraries in Python, JavaScript, Go, and Java make it accessible across common application development stacks.$q$, $q$Cloud-native architecture supports horizontal scaling and fault tolerance for production workloads handling large volumes of vector data.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('54fd0b15-5a7f-4cba-b221-60d8ab928a87', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Weaviate database is free and open source under the Apache 2.0 license, so developers can self-host it on their own infrastructure at no software cost, paying only for their own compute and storage.$q$, $q$Weaviate Cloud, the managed hosting option, includes a free sandbox tier for experimentation, followed by paid Standard tier plans generally priced in the range of 25 to 200 dollars per month, billed roughly by vector dimensions stored.$q$, $q$Higher Professional and Business Critical tiers, starting around 135 and 450 dollars per month respectively, add production-grade availability, support, and scaling for larger workloads, while large enterprise deployments are priced through custom quotes.$q$]::text[], 2);
