-- Enrichment marathon batch: Warmly, WATI, Wave, Wazo, Wazuh, WBO, Weave, Weaviate

-- ── Warmly ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$AI-powered website visitor identification and intent data platform that de-anonymizes B2B site traffic and automatically triggers sales outreach.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free plan for up to 500 de-anonymized visitors per month; paid plans start in the hundreds of dollars per month$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Warmly Review 2026: Features, Pricing, and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See what Warmly does, how its visitor identification and intent data pricing works, and whether this AI sales orchestration platform fits your GTM stack.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Warmly is a B2B go-to-market platform, founded around 2019 in San Francisco by Maximus Greenwald and Carina Pontillo, that identifies anonymous website visitors and turns that traffic into pipeline. It combines website visitor de-anonymization (identifying both companies and, where possible, individual contacts visiting a site), intent data aggregation from providers such as Clearbit, Demandbase, Apollo, and Bombora, and AI-driven orchestration that automatically triggers outbound actions while a visitor is still on the site. Typical workflows include alerting an assigned sales rep in Slack the moment a high-intent account lands on a pricing page, launching an AI chatbot conversation, queuing a personalized email, or adding the visitor to a LinkedIn outreach sequence. Warmly went through the Y Combinator Summer 2020 batch and has raised venture funding including a Series A round backed by investors such as RTP Global, Felicis, and NFX, with total funding in the tens of millions of dollars. The company is generally described as a mid-size startup with roughly 100 employees as of recent reporting. Warmly targets B2B SaaS revenue teams, particularly sales development, demand generation, and revenue operations functions at small and mid-market companies that want to convert anonymous website traffic into identified pipeline without manually building outbound lists. The platform integrates with common CRM and sales engagement tools and with Slack for real-time alerting. Pricing follows a freemium model: a free tier reveals a limited number of de-anonymized visitors per month, while paid plans scale visitor volume, add multi-channel orchestration (chat, email, LinkedIn), and unlock more CRM and enrichment integrations. Reported paid tiers have ranged from several hundred dollars per month for growth-stage teams up to enterprise pricing for larger visitor volumes and more advanced AI agent features. Because Warmly relies on IP-to-company matching and third-party enrichment data, identification accuracy and coverage vary by traffic source, company size, and geography, and person-level identification is inherently more limited than company-level identification due to privacy constraints. Warmly is best understood as part of the broader website visitor identification and intent data category, competing with tools like Clearbit Reveal, RB2B, Leadfeeder, and 6sense on the specific angle of pairing identification with automated, in-the-moment orchestration rather than just reporting.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4acb5d47-918c-44a6-ad53-de5ddb07110f';

