-- ── Wave ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free accounting and invoicing software for small businesses, offering bookkeeping, payments, and payroll, owned by H&R Block.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Starter plan); Pro plan from $19 per month$q$, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE($q$201-500 employees$q$, company_size),
  headquarters = COALESCE($q$Toronto, Ontario, Canada$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Wave Accounting Review 2026: Pricing, Features, and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Wave's free accounting and invoicing software works, what Pro and Payroll cost, and whether it fits your small business bookkeeping needs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Wave, marketed at waveapps.com, is accounting, invoicing, and financial software built for small businesses, freelancers, and sole proprietors. Wave Accounting Inc. was founded in Toronto, Canada, in 2009 by Kirk Simpson and James Lochrie, and launched publicly in 2010 with a free bookkeeping and invoicing product funded initially through a freemium model that later monetized via payment processing and payroll add-ons. In June 2019, tax preparation company H&R Block announced it would acquire Wave for approximately 405 million US dollars (roughly 537 million Canadian dollars), and the acquisition closed in July 2019; Wave has operated as a subsidiary of H&R Block since then while continuing to run out of Toronto. At the time of acquisition, Wave reported serving more than 400,000 small businesses across over 200 countries. The core Wave platform covers double-entry accounting, unlimited invoicing and estimates, receipt scanning, income and expense tracking, and financial reporting, with an add-on Wave Payroll product for running payroll and handling payroll tax calculations and filings in supported US states and Canadian provinces, plus Wave Payments for accepting online card and bank payments on invoices. Wave's pricing structure centers on a free Starter plan that covers manual bookkeeping, invoicing, and expense tracking without automatic bank feeds or receipt scanning, and a paid Pro plan priced around 19 US dollars per month (about 25 Canadian dollars) that adds automatic bank transaction imports, receipt scanning, multiple users, and removal of Wave branding from invoices. Wave Payroll is billed separately as an add-on with a base monthly fee plus a per-employee or per-contractor charge, and Wave also offers optional bookkeeping support services staffed by human bookkeepers for businesses that want hands-on help, priced at a higher monthly rate. Wave targets solo entrepreneurs, freelancers, and very small businesses that need straightforward accounting without the complexity or cost of platforms like QuickBooks or Xero, and it remains one of the best-known free options in the small business accounting software category.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e5e2d12b-a101-4a07-8262-007ffad934e6';

