-- ── Wazo ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open source unified communications platform for building programmable voice, video, messaging, and call center infrastructure.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free (open source); commercial hosting and support available through Wazo.io$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Quebec City, Quebec, Canada$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Wazo Platform Review 2026: Open Source PBX and UC Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn what Wazo Platform offers as an open source unified communications and PBX system, its architecture, pricing, and use cases.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Wazo Platform is an open source unified communications (UC) and PBX system for building carrier-grade, programmable IP telephony infrastructure. It was created in November 2016 in Quebec City, Canada, by a development team led by Sylvain Boily, who had earlier founded the XiVO open source telephony project in 2005; Wazo effectively continues and modernizes that lineage after the shutdown of its predecessor company, Proformatique Inc. Wazo is built primarily on top of the Asterisk PBX engine along with components like Kamailio and RTPEngine, and it exposes REST APIs, WebRTC, WebSockets, and webhooks so developers can integrate and extend telephony, chat, video conferencing, call center queues, voicemail, and presence features into other applications rather than treating the PBX as a closed appliance. The platform can be deployed on bare metal servers, virtual machines, or containers, and its distinctive components are distributed under the GPLv3 open source license, keeping the core stack free to self-host and modify. In addition to the open source community project at wazo-platform.org, there is a related commercial entity, Wazo (via wazo.io), that offers a white-label unified communications platform aimed at managed service providers (MSPs) and carriers who want to resell hosted PBX and UC services under their own brand, layering commercial support, hosting, and multi-tenant management on top of the open source foundation. Wazo's feature set targets class 5 telephony capabilities typically associated with carrier-grade phone systems: audio and video calling, team chat, conferencing, call queues and call centers, voicemail, and mobility features for remote and softphone users. Because it is open source and self-hostable, Wazo appeals most to telecom-savvy organizations, MSPs, developers building custom communications products, and organizations wanting to avoid vendor lock-in associated with proprietary hosted PBX or UCaaS providers. There is no fixed subscription price for the open source core; costs instead come from self-hosting infrastructure, optional commercial support contracts, or white-label hosted plans through the Wazo.io commercial offering, which are typically quoted per deployment or per seat for MSP and carrier customers.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '688d8396-0ab3-420a-ba26-729121f64809';

