-- ── Wazuh ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open source security platform unifying SIEM and XDR for threat detection, log analysis, compliance, and incident response.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free (open source); Wazuh Cloud managed service priced on request$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$San Jose, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Wazuh Review 2026: Open Source SIEM and XDR Explained$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Wazuh's open source SIEM and XDR platform works, what its free and cloud pricing looks like, and where it fits in a security stack.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Wazuh is a free and open source security platform that unifies SIEM (security information and event management) and XDR (extended detection and response) capabilities for monitoring endpoints and cloud workloads. The Wazuh company was founded in 2015 and is headquartered in San Jose, California, growing out of an earlier fork of the OSSEC host-based intrusion detection project into a broader, actively maintained security monitoring platform. The Wazuh architecture consists of lightweight agents installed on monitored endpoints (servers, workstations, cloud instances, and containers) that collect logs, file integrity data, system inventory, and configuration information, which are then sent to a central Wazuh server for analysis, correlation, and alerting, with results visualized through an integrated dashboard built on OpenSearch. Core capabilities include log data analysis, file integrity monitoring, vulnerability detection, configuration assessment against benchmarks like CIS, intrusion and malware detection, incident response automation (active response), and regulatory compliance support for frameworks such as PCI DSS, HIPAA, and GDPR. Because Wazuh is fully open source with no licensing cost, organizations can self-host the entire stack (agents, server, and dashboard) for free, an approach favored by security teams that want full data control, no vendor lock-in, or a lower-cost alternative to commercial SIEM platforms like Splunk or IBM QRadar. For teams that prefer not to manage the infrastructure themselves, Wazuh also offers Wazuh Cloud, a managed hosting and support service with custom, quote-based pricing rather than fixed public rates. The project has an active open source community, extensive documentation, and integrations with major cloud providers (AWS, Azure, Google Cloud), container platforms, and threat intelligence feeds. Wazuh is widely used by security operations center (SOC) teams, managed security service providers (MSSPs), and IT teams at organizations of all sizes that need centralized threat detection and compliance monitoring without the licensing costs typically associated with enterprise SIEM and XDR products.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e60f5b02-2824-43ca-a32f-0fbe7c20da50';

