-- ── WBO ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open source online whiteboard for real-time collaborative drawing and sketching, built and maintained by an independent developer.$q$, short_description),
  pricing_model = COALESCE($q$free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Independent open source project (single primary maintainer)$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$WBO Review 2026: Free Open Source Collaborative Whiteboard$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn what WBO (Whiteboard Online) offers as a free, open source real-time collaborative whiteboard, plus how to use or self-host it.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$WBO, short for Whiteboard Online and also known by its open source project name whitebophir, is a free, simple, real-time collaborative whiteboard built and maintained by independent developer Ophir Lojkine. The publicly hosted demonstration instance runs at wbo.ophir.dev, while the underlying open source code is published on GitHub under the repository name whitebophir and is licensed under the GNU Affero General Public License v3.0 (AGPLv3). Unlike venture-backed collaboration platforms, WBO is a small, community-maintained tool rather than a company with employees, funding rounds, or a formal headquarters; it is best understood as a personal open source project that has grown a meaningful user base due to its simplicity and zero-cost access. The core product lets any number of users draw simultaneously on a shared virtual whiteboard, with changes synced in real time to everyone connected and the board's state persisted so work is not lost between sessions. To collaborate, a user simply shares the board's URL; boards can be created with a random, hard-to-guess name to function as a de facto private space accessible only to people who have the link, since there is no formal account or login system on the hosted version. The interface supports basic drawing tools, shapes, text, and image insertion, and the project has been translated into more than 15 languages, with reports that it ranks among the more popular free online whiteboard tools in some regions, including Russia and Ukraine. Because the code is open source and lightweight (built on Node.js), organizations or individuals who want a private, self-hosted whiteboard instance, for example for internal company use or to avoid relying on the public demo server, can deploy their own copy relatively easily, including via Docker. WBO does not offer paid plans, premium tiers, enterprise features, or SSO, and it lacks the polish, template libraries, and integrations of commercial whiteboard products like Miro or FigJam. It is best suited for lightweight, ad hoc collaborative sketching, teaching, brainstorming, or quick diagramming where cost, simplicity, and self-hosting matter more than advanced features.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6dfb48ec-e418-4fe0-93c7-9323f4ba54ce';

