-- ── Weaviate ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open source AI-native vector database for building semantic search, retrieval-augmented generation, and generative AI applications.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (open source, self-hosted); Weaviate Cloud from around $25 per month$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Amsterdam, Netherlands$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Weaviate Review 2026: Open Source Vector Database Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn how Weaviate's open source vector database works for AI search and RAG, plus its self-hosted and cloud pricing options.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Weaviate is an open source, AI-native vector database designed for building semantic search, retrieval-augmented generation (RAG), and other generative AI applications at scale. The company was founded in 2019 by Bob van Luijt (CEO) and Etienne Dilocker (CTO) and is headquartered in Amsterdam, Netherlands, operating as a remote-first team with employees across many countries. Weaviate stores both data objects and their vector embeddings together, combining vector similarity search with structured filtering, keyword-based (BM25) search, and hybrid search in a single query interface, along with built-in support for reranking and generative search modules that connect retrieved results directly to large language models for RAG pipelines. The core database is released under the Apache 2.0 open source license and can be self-hosted on a developer's own infrastructure, integrated with popular machine learning model providers (such as OpenAI, Cohere, and Hugging Face) for generating embeddings, and used through client libraries in languages including Python, JavaScript, Go, and Java. The company has raised significant venture funding, including a 16 million dollar Series A round in February 2022 led by NEA and a 50 million dollar Series B round in April 2023 led by Index Ventures with participation from Battery Ventures and existing investors, funding used to expand engineering and to build out Weaviate Cloud, the company's managed hosting offering. Weaviate's pricing spans three tiers: the open source database is free to self-host with only infrastructure costs; Weaviate Cloud offers a free sandbox for experimentation plus paid Standard tier plans generally in the range of 25 to 200 dollars per month priced by vector dimensions stored (commonly cited around 0.095 dollars per million vector dimensions), with Professional and Business Critical tiers starting around 135 and 450 dollars per month respectively for production workloads requiring higher availability and support; and custom enterprise pricing for large-scale or dedicated deployments. Weaviate competes in the fast-growing vector database category against products like Pinecone, Milvus, Qdrant, and Chroma, and is commonly used by developers and AI teams building semantic search engines, recommendation systems, chatbots, and RAG-based applications on top of large language models.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '54fd0b15-5a7f-4cba-b221-60d8ab928a87';

